function solve(grid, x, y, k) {
    // Create a copy of the grid to avoid modifying the original
    const newGrid = grid.map(row => [...row]);

    // Extract the submatrix
    const submatrix = [];
    for (let i = 0; i < k; i++) {
        const row = [];
        for (let j = 0; j < k; j++) {
            row.push(newGrid[x + i][y + j]);
        }
        submatrix.push(row);
    }

    // Reverse the submatrix
    submatrix.reverse();

    // Put the reversed submatrix back into the grid
    for (let i = 0; i < k; i++) {
        for (let j = 0; j < k; j++) {
            newGrid[x + i][y + j] = submatrix[i][j];
        }
    }

    return newGrid;
}

