func solve(grid [][]int64, x int64, y int64, k int64) [][]int64 {
    // Create a copy of the grid to avoid modifying the original
    newGrid := make([][]int64, len(grid))
    for i := range newGrid {
        newGrid[i] = make([]int64, len(grid[i]))
        copy(newGrid[i], grid[i])
    }

    // Extract the submatrix
    submatrix := make([][]int64, k)
    for i := 0; i < k; i++ {
        submatrix[i] = make([]int64, k)
        for j := 0; j < k; j++ {
            submatrix[i][j] = newGrid[x+i][y+j]
        }
    }

    // Reverse the submatrix
    for i, j := 0, k-1; i < j; i, j = i+1, j-1 {
        submatrix[i], submatrix[j] = submatrix[j], submatrix[i]
    }

    // Put the reversed submatrix back into the grid
    for i := 0; i < k; i++ {
        for j := 0; j < k; j++ {
            newGrid[x+i][y+j] = submatrix[i][j]
        }
    }

    return newGrid
}
